        minCost = Math.min(minCost, cost0_n_minus_1_1);

        // 4. Target $10^{n-1}$
        let cost1_0_n_minus_1 = 0;
        // First must be '1'
        if (s[0] === '0') cost1_0_n_minus_1++;
        // Remaining n-1 must be '0'
        for (let i = 1; i < n; i++) {
            if (s[i] === '1') cost1_0_n_minus_1++;
        }
        minCost = Math.min(minCost, cost1_0_n_minus_1);
    }

    return minCost;
